  async queue(batch: MessageBatch<unknown>, env: Env): Promise<void> {
    for (const message of batch.messages) {
      const body = message.body as Record<string, unknown> | null;
      const type = typeof body?.type === 'string' ? body.type : '';

      if (type === 'workspace_task_created') {
        let payload;
        try {
          payload = parseWorkspaceTaskQueueMessage(message.body);
        } catch (error) {
          const details = error instanceof Error ? error.message : String(error);
          console.error(`[workspace-task-queue] invalid message dropped: ${details}`);
          continue;
        }

        try {
          await processWorkspaceTask(env, payload.workspaceId, payload.taskId);
        } catch (error) {
          const details = error instanceof Error ? error.message : String(error);
          console.error(`[workspace-task-queue] message handling failed: ${details}`);
          if (shouldRetryWorkspaceTaskError(error)) {
            message.retry();
          }
        }
        continue;
      }

      if (type === 'workspace_deployment_requested') {
        let payload;
        try {
          payload = parseWorkspaceDeploymentQueueMessage(message.body);
        } catch (error) {
          const details = error instanceof Error ? error.message : String(error);
          console.error(`[workspace-deploy-queue] invalid message dropped: ${details}`);
          continue;
        }

        try {
          await processWorkspaceDeployment(env, payload.workspaceId, payload.deploymentId);
        } catch (error) {
          const details = error instanceof Error ? error.message : String(error);
          console.error(`[workspace-deploy-queue] message handling failed: ${details}`);
          if (shouldRetryWorkspaceDeploymentError(error)) {
            message.retry();
          }
        }
        continue;
      }

      if (type === 'review_requested') {
        let payload;
        try {
          payload = parseReviewQueueMessage(message.body);
        } catch (error) {
          const details = error instanceof Error ? error.message : String(error);
          console.error(`[review-queue] invalid message dropped: ${details}`);
          continue;
        }

        await handleReviewQueueDispatch(env, payload, message);
        continue;
      }

      let checkpointPayload;
      try {
        checkpointPayload = parseCheckpointJobQueueMessage(message.body);
      } catch (error) {
        const details = error instanceof Error ? error.message : String(error);
        console.error(`[checkpoint-queue] invalid message dropped: ${details}`);
        continue;
      }

      try {
        await processCheckpointJob(env, checkpointPayload.jobId);
      } catch (error) {
        const details = error instanceof Error ? error.message : String(error);
        console.error(`[checkpoint-queue] message handling failed: ${details}`);
        message.retry();
      }
    }
  },
};

import type { AuthContext, Env } from '../types.js';

const DEFAULT_ACCOUNT_ID = 'self-hosted';

interface ApiKeyRecord {
  account_id: string;
  is_admin: number;
}

function isHostedMode(env: Env): boolean {
  return env.NIMBUS_HOSTED === 'true';
}

export function createSelfHostedAuthContext(): AuthContext {
  return {
    accountId: DEFAULT_ACCOUNT_ID,
    isAdmin: true,
    isAuthenticated: false,
    isHostedMode: false,
  };
}

async function sha256Hex(input: string): Promise<string> {
  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(input));
  return Array.from(new Uint8Array(digest))
    .map((byte) => byte.toString(16).padStart(2, '0'))
    .join('');
}

function unauthorizedResponse(): Response {
  return new Response(JSON.stringify({ error: 'API key required', code: 'unauthorized' }), {
    status: 401,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Idempotency-Key, X-Review-Github-Token, X-Nimbus-Api-Key',
    },
  });
}

async function lookupApiKey(env: Env, keyHash: string): Promise<ApiKeyRecord | null> {
  return (await env.DB.prepare('SELECT account_id, is_admin FROM nimbus_api_keys WHERE key_hash = ?')
    .bind(keyHash)
    .first<ApiKeyRecord>()) ?? null;
}

function isPublicApiPath(pathname: string): boolean {
  if (!pathname.startsWith('/api/')) {
    return true;
  }
  if (pathname.startsWith('/api/jobs')) {
    return true;
  }
  return pathname === '/api/system/deploy-readiness' || pathname === '/api/system/review-readiness';
}

export async function authenticateRequest(request: Request, env: Env): Promise<{ authContext: AuthContext } | { response: Response }> {
  if (!isHostedMode(env)) {
    return { authContext: createSelfHostedAuthContext() };
  }

  const pathname = new URL(request.url).pathname;
  if (isPublicApiPath(pathname)) {
    return {
      authContext: {
        accountId: DEFAULT_ACCOUNT_ID,
        isAdmin: false,
        isAuthenticated: false,
        isHostedMode: true,
      },
    };
  }

  const apiKey = request.headers.get('X-Nimbus-Api-Key')?.trim();
  if (!apiKey) {
    return { response: unauthorizedResponse() };
  }

  const keyHash = await sha256Hex(apiKey);
  const record = await lookupApiKey(env, keyHash);
  if (!record) {
    return { response: unauthorizedResponse() };
  }

  const now = new Date().toISOString();
  env.DB.prepare('UPDATE nimbus_api_keys SET last_used_at = ? WHERE key_hash = ?')
    .bind(now, keyHash)
    .run()
    .catch((error: unknown) => {
      const message = error instanceof Error ? error.message : String(error);
      console.warn(`[auth] failed to update key last_used_at: ${message}`);
    });

  return {
    authContext: {
      accountId: record.account_id,
      isAdmin: record.is_admin === 1,
      isAuthenticated: true,
      isHostedMode: true,
    },
  };
}

