const BUNDLE_BASE64_CHUNK_BYTES = 510 * 1024;
const DEFAULT_DIFF_MAX_BYTES = 128 * 1024;
const MAX_DIFF_MAX_BYTES = 2 * 1024 * 1024;
const DEFAULT_FILE_READ_MAX_BYTES = 256 * 1024;
