      new Request('https://example.com/api/jobs/job_abc12345/events'),
      env as never,
      ctx
    );
    assert.equal(eventsResponse.status, 200);
  }

  {
    const env = createWorkerTestEnv({ hosted: true, keyHash: validKeyHash });
    const response = await worker.fetch(new Request('https://example.com/api/reviews/rev_abc123/events'), env as never, ctx);
    assert.equal(response.status, 401);
  }
}

